def decimal_default(obj):
    if isinstance(obj, Decimal):
        return float(obj)
    raise TypeError


def parse_bool(value):
    if isinstance(value, bool):
        return value
    if value is None:
        return None
    return str(value).strip().lower() in {"1", "true", "yes", "y", "on"}


